(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn15"],{"2cb4":function(n,e,t){"use strict";t.r(e);var o=function(){var n=this,e=n.$createElement,o=n._self._c||e;return o("markdown",{attrs:{source:t("91e4")}})},r=[],s=t("2877"),l={},i=Object(s["a"])(l,o,r,!1,null,null,null);i.options.__file="js2.vue";e["default"]=i.exports},"91e4":function(n,e){n.exports="## Javascript高级知识点\n\n### es6语法\n\n#### 模块化的使用和编译环境\nutil1.js\n```js\nexport default {\n  a: 100\n}\n```\nutil2.js\n```js\nexport function fn1(){\n  console.log('fn1')\n}\nexport function fn2(){\n  console.log('fn2')\n}\n```\nindex.js\n```js\n import util1 from './util1.js'\n import { fn1, fn2 } from './util2.js'\n\n console.log(util1)\n fn1()\n fn2()\n```\n开发环境-babel-安装\n```s\n1，电脑有 node 环境，运行npm init\n2，npm install --save-dev babel-core babel-preset-es2015 babel-preset-latest\n3，创建 .babelrc 文件\n  {\n    \"presets\":[\"es2015\",\"latest\"],\n    \"plugins\":[]\n  }\n4，npm install --global babel-cli\n5，babel --version\n6，创建 ./src/index.js\n内容[1,2,3].map(item => item +1);\n运行 babel ./src/index.js\n```\nwebpack\n```js\n// npm install webpack babel-loader --save-dev\n// 配置webpack.config.js\nmodule.exports = {\n  entry:'./src/index.js',\n  output:{\n    path:__dirname,\n    filename:'./build/bundle.js'\n  },\n  module:{\n    rules:[{\n      test:/\\.js?$/,\n      exclude:'(node_modules)',\n      loader:'babel-loader'\n    }]\n  }\n}\n// 配置package.json中的script\n// 运行webapck\n```\n\nrollup.js\n```js\n// rollup功能单一，webpack功能强大\n// 工具要尽量功能单一，可集成，可扩展\n\n// npm init\n// npm install rollup rollup-plugin-node-resolve rollup-plugin-babel babel-plugin-external-helpers babel-preset-latest --save-dev\n// 配置.babelrc\n{\n    \"presets\":[\"latest\",{\n      \"es2015\":{\n        \"modules\":false // 不关心引用的第三方的插件的js\n      }\n    }],\n    \"plugins\":[\"external-helpers\"] \n  }\n// rollup.config.js\nimport babel from 'rollup-plugin-babel'\nimport resolve from 'rollup-plugin-node-resolve'\n\nexport default {\n  entry:'src/index.js',\n  format:'umd', \n  plugins:[\n    resolve(),\n    babel({\n      exclude:'node_modules/*'\n    })\n  ],\n  dest:'build/bundle.js'\n}\n// rollup -c rollup.config.js\n```\n小结\n```\n没有模块化\nAMD成为标准，require.js(也有CMD)\n前端打包工具，nodejs模块化可以被使用\nES6出现，想统一现在所有模块化标准\nnodejs积极支持，浏览器尚未统一\n你可以自造库，但是不要自造标准\n\n语法：import export（注意有无default）\n环境：babel编译ES6语法，模块化可用webpack和rollup\n```\n\n#### Class和JS构造函数的区别\n##### Class\n\n目前使用 class 的场景非常多，例如在使用 React 时\n\n```jsx\nclass Ad extends React.Component {\n    constructor(props) {\n        super(props);\n        this.state = {\n            data: []\n        }\n    }\n    render() {\n        return (\n            <div>hello imooc</div>\n        )\n    }\n    componentDidMount() {\n        \n    }\n}\n```\n\n##### 基本用法\n\nJS 代码\n\n```js\nfunction MathHandle(x, y) {\n  this.x = x;\n  this.y = y;\n}\n\nMathHandle.prototype.add = function () {\n  return this.x + this.y;\n};\n\nvar m = new MathHandle(1, 2);\nconsole.log(m.add())\n```\n\nES6 代码\n\n```js\nclass MathHandle {\n  constructor(x, y) {\n    this.x = x;\n    this.y = y;\n  }\n\n  add() {\n    return this.x + this.y;\n  }\n}\nconst m = new MathHandle(1, 2);\nconsole.log(m.add())\n\n// typeof MathHandle // \"function\"\n// MathHandle === MathHandle.prototype.constructor // true\n// m.__proto__ = MathHandle.prototype // true\n```\n\n`npm start`看一下，可以看到编译出来的代码有许多附加的内容，不在简洁\n\n其实 class 就是 js 构造函数的一个语法糖，连原型链原理都是一样的（**这种语法糖形式，看起来和实际原理不一样的东西，我个人不太赞同**）\n\n```js\nclass MathHandle {\n  // ...\n}\n// 这种语法糖形式，看起来和实际原理不一样的东西，我个人不太赞同\n// 形式上强行模仿 java C# ，却失去了它的本性和个性\n```\n\n另外，使用 class 打包出来的 JS 代码，会有很多冗余附加代码，**这就导致使用发布的代码调试 bug 的时候变得很困难**。\n\n##### 继承\n\n使用 JS 的原型如何实现集成，在《前端 JS 面试技巧》的课程中已经详细讲过。这里再拿一个例子简单回顾一下，\n\n```js\n// 动物\nfunction Animal() {\n    this.eat = function () {\n        console.log('animal eat')\n    }\n}\n// 狗\nfunction Dog() {\n    this.bark = function () {\n        console.log('dog bark')\n    }\n}\nDog.prototype = new Animal()\n// 哈士奇\nvar hashiqi = new Dog()\n```\n\n用 ES6 可以这样编写\n\n```js\nclass Animal {\n    constructor(name) {\n        this.name = name\n    }\n    eat() {\n        console.log(`${this.name} eat`)\n    }\n}\n\nclass Dog extends Animal {\n    constructor(name) {\n        super(name)\n        this.name = name\n    }\n    say() {\n        console.log(`${this.name} say`)\n    }\n}\nconst dog = new Dog('哈士奇')\ndog.say()\ndog.eat()\n```\n\n查看编译出来的 js 代码，会发现冗余代码更多，更加复杂了。\n\n##### 总结\n```\n用 class 做为构造函数，我个人感觉不如直接使用 function ，看起来更加直观，更加接近原理，而且编译出来没有冗余代码\n但是，使用 es6 编写继承，比用 js 编写继承看起来更加统一，不像 js 编写继承那么琐碎。这是因为 class 的设计其实是借鉴了 java C# 这些经典面向对象语言的语法，让 js 看起来更加“面向对象”化\n但是，无论语法怎样写，其中的原理你得明白，它还是逃不出原型和原型链的理论基础\n待 es6 部分讲解完，会带领大家继续深入看 js 原型。\n```\n\n\n#### Promise的用法\n##### Promise\n\n###### 语法\n\njs 写异步一直是很意见很蛋疼的事，总是逃不开回调函数，即传说中的“callback hell”，例如\n\n```js\nfunction loadImg(src, callback, fail) {\n    var img = document.createElement('img')\n    img.onload = function () {\n        callback(img)\n    }\n    img.onerror = function () {\n        fail()\n    }\n    img.src = src\n}\n\nvar src = 'http://www.imooc.com/static/img/index/logo_new.png'\nloadImg(src, function (img) {\n    console.log(img.width)\n}, function () {\n    console.log('failed')\n})\n```\n\n使用 Promise 就是\n\n```js\nfunction loadImg(src) {\n    const promise = new Promise(function (resolve, reject) {\n        var img = document.createElement('img')\n        img.onload = function () {\n            resolve(img)\n        }\n        img.onerror = function () {\n            reject()\n        }\n        img.src = src\n    })\n    return promise   \n}\n\nvar src = 'http://www.imooc.com/static/img/index/logo_new.png'\nvar result = loadImg(src)\n\nresult.then(function (img) {\n    console.log(img.width)\n}, function () {\n    console.log('failed')\n})\n\nresult.then(function (img) {\n    console.log(img.height)\n})\n```\n\n##### 兼容\n\nPromise 在浏览器的兼容已经比较好了，某些不兼容的，可以引入 q.js 或者 bluebird.js\n\n##### 最后\n\n后面会有 js 异步的深入介绍，到时候会详细介绍 Promise 的前生今世，这里显示一下语法。\n\n**为何 Generator 不介绍**\n\nGenerator 语法和实现原理都比较复杂，很难理解。另外，它已经有了很成熟的替代方案，async/await（会再接下来的异步中详细介绍）。还有，它并不是为了解决异步这个问题而产生的，而是恰好被用来解决了异步，因此理解起来比较难。因此，Generator 会慢慢退出历史舞台，被更加简洁的东西代替。\n\n#### ES6其他常用功能\n\n- 搭建 ES6 编译环境：使用 babel 编译，使用 webpack 做模块化处理，后来又介绍了 rollup 做模块化处理\n- modules：关键字`import` `export`\n- 琐碎的功能：let/const，多行字符串/模板变量，解构赋值，块级作用域，函数默认参数，箭头函数\n- class：用法、和原型的关系、继承\n- Promise：用法\n\n#### 原型\n\n#### zepto 是什么\n\n先来看看 zepto 是什么。别以为他很基础，平时用 zepto 很多的，并不一定能注意到这些问题，还是跟我一起看看。\n\n#### demo\n\n先做一个简单的 demo 页面，就平时最基本的使用方式\n\n```html\n    <p>jquery test 1</p>\n    <p>jquery test 2</p>\n    <p>jquery test 3</p>\n\n    <div id=\"div1\">\n        <p>jquery test in div</p>\n    </div>\n\n    <script type=\"text/javascript\" src=\"./jquery-3.2.1.js\"><\/script>\n    <script type=\"text/javascript\">\n        var $p = $('p')\n        $p.css('color', 'red')  // css 是原型方法\n        console.log($p.html())  // html 是原型方法\n\n        var $div1 = $('#div1')\n        $div1.css('color', 'blue')  // css 是原型方法\n        console.log($div1.html())  // html 是原型方法\n    <\/script>\n```\n\n#### zepto 原型如何实现\n\n#### 找到 zepto 对象是哪里创建的\n\n```js\n  // 空对象\n  var zepto = {}\n\n  // 这就是构造函数\n  function Z(dom, selector) {\n    var i, len = dom ? dom.length : 0\n    for (i = 0; i < len; i++) this[i] = dom[i]\n    this.length = len\n    this.selector = selector || ''\n  }\n\n  zepto.Z = function(dom, selector) {\n    // 注意，出现了 new 关键字\n    return new Z(dom, selector)\n  }\n\n  zepto.init = function (selector) {\n    // 源码中，这了的处理情况比较复杂。但因为本次只是针对原型，因此这里就弱化了\n    var slice = Array.prototype.slice\n    var dom = slice.call(document.querySelectorAll(selector))\n    return zepto.Z(dom, selector) \n  }\n\n  // 即使用 zepto 时候的 $\n  var $ = function(selector){\n    return zepto.init(selector)\n  }\n```\n\n#### 找到原型\n\n```js\n$.fn = {\n    constructor: zepto.Z,\n\n    css: function (key, value) {\n\n    },\n    html: function (value) {\n\n    }\n}\n\nzepto.Z.prototype = Z.prototype = $.fn\n```\n\n构造函数`Z`的原型的方法，是在`$.fn`定义完了之后，又赋值给`Z.prototype`的\n\n另外，`constructor`赋值了`zepto.Z`而不是`Z`，这是我不太理解的地方，不过完全不影响使用\n\n#### 最后\n\n以上提到的每一个核心函数，都要完全透彻的理解才行。\n\n#### zepto 看源码\n\n一开始，是一个 umd 规范的封装\n\n接下来 \n\n```js\nvar Zepto = (function () {\n    var $ = function () {\n\n    }\n\n    // 返回核心函数\n    return $\n})\n\n// 暴露全局方法\nwindow.Zepto = Zepto\nwindow.$ === undefined && (window.$ = Zepto)\n\n// 一些扩展，https://github.com/madrobby/zepto#zepto-modules 这些模块都是通过这种方式扩展的\n;(function($) {\n\n})(Zepto)\n\n;(function($) {\n\n})(Zepto)\n\n;(function($) {\n\n})(Zepto)\n```\n\n然后就是上一节讲的那些核心方法\n\n#### jquery 是什么\n\n这一节完全可以照搬“zepto 是什么”那一节的内容，因为两者的基础 API 都是一样的\n\n#### demo\n\n先做一个简单的 demo 页面，就平时最基本的使用方式\n\n```html\n    <p>jquery test 1</p>\n    <p>jquery test 2</p>\n    <p>jquery test 3</p>\n\n    <div id=\"div1\">\n        <p>jquery test in div</p>\n    </div>\n\n    <script type=\"text/javascript\" src=\"./jquery-3.2.1.js\"><\/script>\n    <script type=\"text/javascript\">\n        console.log($)\n\n        var $p = $('p')\n        console.log($p)\n\n        var $div1 = $('#div1')\n        console.log($div1)\n    <\/script>\n```\n\n这里打印出来的俩对象，是什么数据结构呢？—— 类数组，解释一下什么是类数组\n\n还有`console.log($)`别忘了，`$`是一个函数（从`$('p')`就能看出来），传入 selector 返回一个 zepto 对象。\n\n#### 关于原型\n\n`$('p')`返回的`$p`的构造函数是什么？因为`$p.__proto__`等于构造函数的`prototype`\n\n这个构造函数和`$`函数的关系是什么？\n\n#### jquery 原型如何实现\n\njquery 的实现方式比 zepto 要更加绕一些，考验各位的理解能力\n\n核心函数\n\n```js\nvar jQuery = function (selector) {\n    // 注意 new 关键字，第一步就找到了构造函数\n    return new jQuery.fn.init(selector);\n}\n\n// 定义构造函数\nvar init = jQuery.fn.init = function (selector) {\n    var slice = Array.prototype.slice\n    var dom = slice.call(document.querySelectorAll(selector))\n\n    var i, len = dom ? dom.length : 0\n    for (i = 0; i < len; i++) this[i] = dom[i]\n    this.length = len\n    this.selector = selector || ''\n}\n\n// 初始化 jQuery.fn\njQuery.fn = jQuery.prototype = {\n    constructor: jQuery,\n\n    // 其他函数...\n    css: function (key, value) {\n    },\n    html: function (value) {\n    }\n}\n// 定义原型\ninit.prototype = jQuery.fn;\n```\n#### jquery 看源码\n\n一开始，是一个 umd 规范的封装。封装之后，后面函数的返回值，会直接挂在到 window 对象。\n\n然后看代码一开始定义了`jQuery`，最后`return jQuery;`\n\n然后就是上一节将的核心代码\n\n#### 总结\n\n再把最关键的，zepto 和 jquery 的核心代码看一下\n\n#### zepto\n\n```js\n  // 空对象\n  var zepto = {}\n\n  // 这就是构造函数\n  function Z(dom, selector) {\n    var i, len = dom ? dom.length : 0\n    for (i = 0; i < len; i++) this[i] = dom[i]\n    this.length = len\n    this.selector = selector || ''\n  }\n\n  zepto.Z = function(dom, selector) {\n    // 注意，出现了 new 关键字\n    return new Z(dom, selector)\n  }\n\n  zepto.init = function (selector) {\n    // 源码中，这了的处理情况比较复杂。但因为本次只是针对原型，因此这里就弱化了\n    var slice = Array.prototype.slice\n    var dom = slice.call(document.querySelectorAll(selector))\n    return zepto.Z(dom, selector) \n  }\n\n  // 即使用 zepto 时候的 $\n  var $ = function(selector){\n    return zepto.init(selector)\n  }\n```\n\n#### jquery\n\n```js\nvar jQuery = function (selector) {\n    // 注意 new 关键字，第一步就找到了构造函数\n    return new jQuery.fn.init(selector);\n}\n\n// 初始化 jQuery.fn\njQuery.fn = jQuery.prototype = {\n    constructor: jQuery,\n\n    // 其他函数...\n    addClass: function () {\n\n    },\n    html: function () {\n        \n    }\n}\n\n// 定义构造函数\nvar init = jQuery.fn.init = function (selector) {\n    // 源码中，这了的处理情况比较复杂。但因为本次只是针对原型，因此这里就弱化了\n    var slice = Array.prototype.slice\n    return slice.call(document.querySelectorAll(selector))\n}\n\n// 定义原型\ninit.prototype = jQuery.fn;\n```\n\n#### 为何要把原型方法都放在`jQuery.fn`或者`$.fn`？\n\n以 jquery 为例，构造函数本来不是`jQuery`，为何要把对象原型放在`jQuery.fn`，即`jQuery.prototype`？\n\n```js\n// 因为要扩展插插件，做一个简单的插件的例子\n\n$.fn.getNodeName = function () {\n    return this[0].nodeName\n}\n```\n\n#### 扩展知识\n\n面试官为何那么执着的问：是否了解 xxx 的源码\n\n\n\n### 异步\n#### 什么是单线程，和异步有何关系\n#### 什么是event-loop 时间轮询\n#### 目前JS解决异步的方案有哪些\n#### 如果只用jquery如何解决异步\n#### Promise的标准\n#### async/await的使用（ES7）\n\n### vdom\n#### 什么是vdom，为何要用vdom\n#### vdom如何使用，核心函数有哪些\n#### 了解diff算法吗？\n\n### MVVM（vue）\n#### 之前使用jquery和现在使用vue或React框架的区别\n#### 你如何理解MVVM\n#### vue如何实现响应式\n#### vue如何解析模板\n#### 介绍vue的实现流程\n\n### 组件化（react）\n#### 对组件化的理解\n#### JSX是什么？\n#### JSX和vdom什么关系\n#### 简述React的setState\n#### 阐述自己如何比较React和vue\n\n### hybird\n#### hybrid是什么，为何要用hybrid\n#### hybrid如何更新上线\n#### hybrid和h5有何区别\n#### JS如何与客户端通信\n"}}]);